<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>2048</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background-color: #1a1a2e;
            color: #eee;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
        }

        h1 {
            font-size: 3em;
            margin-bottom: 20px;
            color: #fff;
            letter-spacing: 4px;
        }

        .header {
            display: flex;
            align-items: center;
            gap: 20px;
            margin-bottom: 20px;
        }

        #score-container {
            background-color: #16213e;
            padding: 10px 24px;
            border-radius: 8px;
            font-size: 1.2em;
            min-width: 120px;
            text-align: center;
        }

        #reset {
            background-color: #0f3460;
            color: white;
            border: none;
            padding: 10px 24px;
            border-radius: 8px;
            font-size: 1em;
            cursor: pointer;
            transition: background-color 0.2s;
        }

        #reset:hover {
            background-color: #533483;
        }

        #board-wrapper {
            position: relative;
        }

        #board {
            display: grid;
            grid-template-columns: repeat(4, 100px);
            grid-template-rows: repeat(4, 100px);
            gap: 12px;
            background-color: #16213e;
            padding: 15px;
            border-radius: 12px;
        }

        .cell {
            width: 100px;
            height: 100px;
            background-color: #0f3460;
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: bold;
        }

        .cell[data-value="2"]    { background-color: #3a7bd5; color: white; }
        .cell[data-value="4"]    { background-color: #5b8def; color: white; }
        .cell[data-value="8"]    { background-color: #f093fb; color: #1a1a2e; }
        .cell[data-value="16"]   { background-color: #eb5781; color: white; }
        .cell[data-value="32"]   { background-color: #f48024; color: white; }
        .cell[data-value="64"]   { background-color: #e94f3c; color: white; }
        .cell[data-value="128"]  { background-color: #d4a574; color: #1a1a2e; font-size: 1.5em; }
        .cell[data-value="256"]  { background-color: #c99039; color: white; font-size: 1.5em; }
        .cell[data-value="512"]  { background-color: #b87333; color: white; font-size: 1.5em; }
        .cell[data-value="1024"] { background-color: #9e6b30; color: white; font-size: 1.2em; }
        .cell[data-value="2048"] { background-color: #7a5c3d; color: white; font-size: 1.2em; }
    </style>
</head>
<body>
    <h1>2048</h1>
    <div class="header">
        <div id="score-container">Score: <span id="score">0</span></div>
        <button id="reset">New Game</button>
    </div>
    <div id="board-wrapper">
        <div id="board"></div>
    </div>

    <script>
        // ── Internal state ───────────────────────────────────────────────
        let board = [];   // 4×4 array, 0 = empty
        let score = 0;

        // ── Helpers ──────────────────────────────────────────────────────
        function deepCopy(arr) { return arr.map(r => [...r]); }

        // Slide and merge a single row toward the left.
        // Each tile merges at most once per call (left-to-right pass).
        function slideAndMergeLeft(row) {
            let nonZero = [];
            for (let i = 0; i < 4; i++) if (row[i] !== 0) nonZero.push(row[i]);

            let merged = [];
            for (let i = 0; i < nonZero.length; i++) {
                if (merged.length > 0 && merged[merged.length - 1] === nonZero[i]) {
                    let val = merged.pop() * 2;
                    score += val;
                    merged.push(val);
                } else {
                    merged.push(nonZero[i]);
                }
            }

            while (merged.length < 4) merged.push(0);
            return merged;
        }

        // ── Core game logic ──────────────────────────────────────────────
        function init() {
            board = Array.from({ length: 4 }, () => Array(4).fill(0));
            score = 0;
            spawnTile();
            spawnTile();
            renderBoard();
            updateScore();
        }

        // Place a new tile (2 with 90% probability, 4 otherwise) on a random empty cell.
        function spawnTile() {
            let empties = [];
            for (let i = 0; i < 4; i++)
                for (let j = 0; j < 4; j++)
                    if (board[i][j] === 0) empties.push({ i, j });

            if (empties.length > 0) {
                let c = empties[Math.floor(Math.random() * empties.length)];
                board[c.i][c.j] = Math.random() < 0.9 ? 2 : 4;
            }
        }

        function move(direction) {
            let oldBoard = JSON.stringify(board);

            if (direction === 'left') {
                for (let i = 0; i < 4; i++) board[i] = slideAndMergeLeft(board[i]);
            } else if (direction === 'right') {
                for (let i = 0; i < 4; i++) {
                    let rev = [...board[i]].reverse();
                    board[i] = slideAndMergeLeft(rev).reverse();
                }
            } else if (direction === 'up') {
                // transpose → move left on rows → transpose back
                let t = [];
                for (let j = 0; j < 4; j++) {
                    let col = [];
                    for (let i = 0; i < 4; i++) col.push(board[i][j]);
                    t.push(col);
                }
                for (let i = 0; i < 4; i++) t[i] = slideAndMergeLeft(t[i]);
                board = [];
                for (let j = 0; j < 4; j++) {
                    let row = [];
                    for (let i = 0; i < 4; i++) row.push(t[i][j]);
                    board.push(row);
                }
            } else if (direction === 'down') {
                // transpose → reverse rows → move left → reverse rows → transpose back
                let t = [];
                for (let j = 0; j < 4; j++) {
                    let col = [];
                    for (let i = 0; i < 4; i++) col.push(board[i][j]);
                    t.push(col);
                }
                for (let i = 0; i < 4; i++) t[i] = t[i].reverse();
                for (let i = 0; i < 4; i++) t[i] = slideAndMergeLeft(t[i]);
                for (let i = 0; i < 4; i++) t[i] = t[i].reverse();
                board = [];
                for (let j = 0; j < 4; j++) {
                    let row = [];
                    for (let i = 0; i < 4; i++) row.push(t[i][j]);
                    board.push(row);
                }
            }

            let newBoard = JSON.stringify(board);
            let changed = oldBoard !== newBoard;

            if (changed) spawnTile();
            renderBoard();
            updateScore();

            return changed;
        }

        // Set the grid exactly — no tile is spawned.
        function setBoard(arr) {
            board = arr.map(r => [...r]);
            renderBoard();
            updateScore();
        }

        // ── UI rendering ─────────────────────────────────────────────────
        function updateScore() {
            document.getElementById('score').textContent = score;
        }

        function renderBoard() {
            const el = document.getElementById('board');
            el.innerHTML = '';
            for (let i = 0; i < 4; i++) {
                for (let j = 0; j < 4; j++) {
                    let cell = document.createElement('div');
                    cell.className = 'cell';
                    if (board[i][j] !== 0) {
                        cell.textContent = board[i][j];
                        cell.setAttribute('data-value', board[i][j]);
                    }
                    el.appendChild(cell);
                }
            }
        }

        // ── Input handling ───────────────────────────────────────────────
        document.addEventListener('keydown', e => {
            if (['ArrowLeft','ArrowRight','ArrowUp','ArrowDown'].includes(e.key)) {
                e.preventDefault();
                let dir;
                switch (e.key) {
                    case 'ArrowLeft':   dir = 'left'; break;
                    case 'ArrowRight':  dir = 'right'; break;
                    case 'ArrowUp':     dir = 'up'; break;
                    case 'ArrowDown':   dir = 'down'; break;
                }
                move(dir);
            }
        });

        document.getElementById('reset').addEventListener('click', init);

        // ── Public API (required for grading) ────────────────────────────
        window.game = {
            size: 4,
            reset: init,
            move: move,
            board: function () { return deepCopy(board); },
            setBoard: setBoard,
            score: function () { return score; }
        };

        // ── Start ────────────────────────────────────────────────────────
        init();
    </script>
</body>
</html>
